<template>
  <div>
    <br><br><br><br>
<div>
<table bgcolor="#ffffff" border="0" bordercolor="#e8f6f7" cellpadding="0" cellspacing="0" class="BK" height="20%" width="20%">
	<tbody>
		<tr>
			<td align="center" @click="pageBackOFF()" > <img border="0" height="103" :src="requireImg('images/dt.png')" width="103" /> </td>

		</tr>

		<tr>
			<td align="center" @click="pageBackON()"> <img border="0" height="103" :src="requireImg('images/dt.png')" width="103" /> </td>

		</tr>
		
	</tbody>
</table>
	<br><br><br><br>
	<input type='button' @click="setTooBar(0)" value='去除toolbar（全屏）'></input>
	<input type='button' @click="setTooBar(1)" value='恢复toolbar（默认）'></input>
	<br><br><br><br>
	<br><br><br><br>
	<input type='button' @click="globalSecure(0)" value='允许截屏'></input>
	<input type='button' @click="globalSecure(1)" value='禁止截屏'></input>
	<br><br><br><br>
	 <input type='button' @click="screenControl(0)" value='横屏'></input>
	 <input type='button' @click="screenControl(1)" value='竖屏'></input>
	 <input type='button' @click="screenControl(2)" value='恢复默认'></input><br><br><br><br>
	
	<input type='button' @click="executeGoToScanPager()"  value='资源生成二维码 快速扫码填入信息'></input>&nbsp;&nbsp;&nbsp;&nbsp;<br><br>
	<textarea   rows="5" cols="40" id='diyUrl' placeholder='输入文件URL'></textarea><br><br>
	<input type='button' @click="openUrl()"  value='访问'></input>&nbsp;&nbsp;&nbsp;&nbsp;<br><br>


</div>
  </div>
</template>

<script>
export default {
  name: "pageBack", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      dataProps: "",
    };
  },
  computed: {},
  created() {},
  mounted() {
    document.addEventListener("pause", this.onApplicationBackground);
    document.addEventListener("resume", this.onApplicationForeground);
    // 添加事件监听

    document.addEventListener("load", function () {
      console.log("横竖屏监听");
      this.orientationChange();

      window.onorientationchange = this.orientationChange;
    });
    this.$once("hook:beforeDestroy", () => {
      document.removeEventListener("pause", this.onApplicationBackground);
      document.removeEventListener("resume", this.onApplicationForeground);
      document.removeEventListener("load", function () {
        console.log("横竖屏监听");
        this.orientationChange();

        window.onorientationchange = this.orientationChange;
      });
    });
  },
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    /**	
		pause
		当应用程序进入后台时触发事件。
		resume
		当应用程序从后台返回时，会触发事件。
		**/

    //前台
    onApplicationForeground() {
      console.info("onApplicationForeground	应用程序从后台返回了");
    },

    //后台
    onApplicationBackground() {
      console.info("onApplicationBackground	应用程序进入后台运行");
    },

    /**
     *	名称：回退按钮 开关
     *	方法名称：setBackButton
     *	适用平台：移动门户 、(电力一点通 暂时不可用)
     *	负责人：
     *	开发日期：
     *	版本：1.1
     *	参数说明：
     *			backType: 0代表不可返回，1代表可以返回
     *	回调说明：
     *		successCallback
     *		errorCallback
     *	方法说明：
     *		页面加载时执行onLoad方法，
     *		deviceReady 标识cordova环境是否准备好,初始值为false
     *		onDeviceReady 表示cordova加载完毕
     **/
    /**
     *调用此插件，客户端及移动门户title 回退按钮失效
     *成功回调 与 失败退到
     **/
    pageBackOFF() {
      alert("回退按钮失效，禁止回退");
      mam.navigator.appmenu.setBackButton(successCallback, errorCallback, "0");
      alert("回退按钮已经失效");
    },
    pageBackON() {
      alert("回退按钮放开，允许回退");
      mam.navigator.appmenu.setBackButton(successCallback, errorCallback, "1");
      alert("允许回退");
    },
    successCallback() {
      alert("successCallback");
    },
    errorCallback() {
      alert("errorCallback");
    },

    setTooBar(type) {
      alert(type);
      mam.navigator.appmenu.setTooBar(this.setTooBarcallback, type);
    },
    setTooBarcallback(obj) {
      alert("全屏设置成功 " + JSON.stringify(obj));
    },

    screenControl(type) {
      alert(type);
      //parame  0 横屏	1竖屏	2默认显示
      mam.navigator.appmenu.screenControl(this.screenControlcallback, type);
    },

    globalSecure(type) {
      alert(type);
      //parame  0 允许截屏	1 禁止截屏
      mam.navigator.appmenu.globalSecure(this.screenControlcallback, type);
    },

    screenControlcallback(obj) {
      alert("成功回调 " + JSON.stringify(obj));
    },

    /************************************************/
    // 判断屏幕是否旋转

    orientationChange() {
      switch (window.orientation) {
        case 0:
          alert(
            "肖像模式 0,screen-width: " +
              screen.width +
              "; screen-height:" +
              screen.height
          );
          break;
        case -90:
          alert(
            "左旋 -90,screen-width: " +
              screen.width +
              "; screen-height:" +
              screen.height
          );
          break;
        case 90:
          alert(
            "右旋 90,screen-width: " +
              screen.width +
              "; screen-height:" +
              screen.height
          );
          break;
        case 180:
          alert(
            "风景模式 180,screen-width: " +
              screen.width +
              "; screen-height:" +
              screen.height
          );
          break;
      }
    },

    openUrl() {
      var fileUrl = document.getElementById("diyUrl").value;
      window.open(fileUrl, "_blank");
    },

    /**
	//到扫描界面
**/
    executeGoToScanPager() {
      console.log("executeGoToScanPager()-->start");
      if (!deviceReady) {
        console.log("Cordova is not ready,return");
        return;
      }
      //获取平台信息
      var devicePlatform = device.platform;
      //document.getElementById("list").innerHTML = "";
      //执行到这边表示cordova环境准备完成,在二维码扫描界面
      mam.navigator.forward.goToScanTwoDiemCode(successCallback, errorCallback);

      //执行成功回调
      //这边参数表示扫描成功后返回的字符串
      function successCallback(msg) {
        console.log("successCallback() msg:" + msg);
        //alert("11");
        document.getElementById("diyUrl").value = msg;
      }

      //执行失败回调[扫描失败，暂不退出界面未做处理]
      function errorCallback(msg) {
        console.log("errorCallback() msg:" + msg);
        //document.getElementById("list").innerHTML = "";
      }
    },
    requireImg(url) {
      return require("@/assets/" + url);
    },
  },
};
</script>
<style lang='css' scoped>
